VALUES
  ('investigation-d4d4f144-moex-00016', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '關於憲法保障之隱私權，下列敘述何者正確？', '["在公開場域活動，絕對不會受到隱私權的保護", "指紋為重要個人資訊，個人對指紋的控制受到資訊隱私權保障", "為維護交通安全，一般社區於街頭裝設之監視攝影器應提供警察機關取締交通違規之用", "個人於公開場域得主張有不受他人注視、接近之隱私權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00017', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '依憲法增修條文規定，關於覆議制度，下列敘述何者錯誤？', '["行政院得提起覆議之標的，限於立法院決議之法律案、預算案及條約案", "就立法院決議通過、總統公布之法律，行政院於執行時，如發現有窒礙難行之處，得經總統核可， 提出覆議", "立法院對於行政院移請覆議案，原則上應於送達15日內作成決議", "覆議時，如經全體立法委員二分之一以上決議維持原案，行政院院長應即接受該決議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00018', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '憲法有關監察院的設計，下列敘述何者正確？', '["現行監察院具有民意代表機關的性質", "監察院應超越黨派，獨立行使職權，故擔任監察委員後，不得參與政黨活動", "現行制度，監察院設院長、副院長各一人，由監察委員互選之", "監察委員19人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00019', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '依憲法、相關大法官解釋及憲法法庭裁判，有關地方自治敘述，下列敘述何者正確？', '["直轄市、縣市及鄉鎮市自治均受憲法保障", "地方自治團體的地位，類似行政機關", "我國是單一國體制，即使是憲法保障之地方自治事項，仍受憲法及中央法律之拘束，且不得牴觸憲 法及中央法律規定", "只要與居民有切身的事項，皆屬地方自治事項，地方自治團體得超越中央法規，自訂自治條例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00020', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', 'A股份有限公司（以下簡稱A公司）持有B股份有限公司（以下簡稱B公司）百分之百股份，關於 二者之關係，下列敘述何者錯誤？', '["B公司不得購買A公司之股份", "A公司之董事不得身兼B公司之董事", "B公司如持有A公司之股份，不得於A公司股東會中行使表決權", "B公司為一人股東之股份有限公司，所以B公司之股東會職權由董事會行使"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00021', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '依據性別平等工作法之規定，下列敘述何者正確？①女性受僱者每月得請生理假1日  ②受僱者於其', '["為審議性別平等工作事項，主管機關應設 性別平等工作會", "受僱於僱用30人以上雇主之受僱者，為撫育2歲子女，得向雇主請求每天減少 工作時間1小時，減少之工作時間，並得請求報酬", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00022', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '依我國憲法及增修條文規定，下列關於監察院之敘述，何者錯誤？', '["監察院為國家最高監察機關，行使同意、彈劾、糾舉及審計權", "監察院對於中央公務人員之彈劾，須經監察委員2人以上之提議，9人以上之審查及決定，始得提出", "監察院為行使監察權，得向行政院調閱各種有關文件", "監察委員須超出黨派以外，依據法律獨立行使職權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
  ('investigation-d4d4f144-moex-00023', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '檢察官張三明知李四並未犯罪，仍予以起訴，以報私怨。下列敘述何者正確？', '["張三的行為構成刑法第125條第1項的濫用職權追訴罪，因其係有追訴犯罪職務之公務員", "張三的行為構成刑法第125條第1項的濫用職權追訴罪，因其係有審判職務之公務員", "張三的行為不構成刑法第125條第1項的濫用職權追訴罪，因檢察官係獨立行使職權", "張三的行為不構成刑法第125條第1項的濫用職權追訴罪，因李四有罪與否，仍須由法官審判"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL),
