  ('investigation-d4d4f144-moex-00025', 'investigation-d4d4f144', 'investigation-d4d4f144-moex-114-44c4f898', 'sub-investigation-d4d4f144-03', NULL, 'single_choice', '雇主與勞工為離職後競業禁止之約定時，關於約定之期間，下列敘述何者正確？', '["最長不得逾5年，逾5年者，其約定無效", "最長不得逾4年，逾4年者，其約定無效", "最長不得逾3年，逾3年者，縮短為3年", "最長不得逾2年，逾2年者，縮短為2年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:38+00:00", "source_pdf_sha1": "904ad8d12125", "answer_pdf_sha1": "7bd301720801", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "411", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "財經實務組"}'::jsonb, NULL)
